import (
	context "context"
	fern "github.com/request-body-unwrap/fern"
	fernclient "github.com/request-body-unwrap/fern/client"
)

client := fernclient.NewClient()
response, err := client.Payment.CreatePayment(
	context.TODO(),
	&fern.CreatePaymentRequest{
		Data: &fern.CreatePaymentRequestData{
			Type: fern.CreatePaymentRequestDataTypePayment,
			Attributes: &fern.CreatePaymentRequestDataAttributes{
				Amount:   1,
				Currency: "currency",
			},
		},
	},
)

